const express = require('express');
const fs = require('fs');
const path = require('path');

const app = express();
const port = 3000;

// Load plugins from configuration files or environment variables
function loadPlugins() {
    const pluginConfig = process.env.PLUGINS || 'plugins.json';
    try {
        const config = JSON.parse(fs.readFileSync(pluginConfig, 'utf8'));
        return config.plugins.map(plugin => require(path.resolve(__dirname, plugin.path)));
    } catch (error) {
        console.error('Failed to load plugins:', error);
        return [];
    }
}

const plugins = loadPlugins();

// Middleware to apply plugins
function applyPlugins(req, res, next) {
    let index = 0;
    function runPlugin() {
        if (index < plugins.length) {
            const plugin = plugins[index++];
            try {
                plugin(req, res, runPlugin);
            } catch (error) {
                console.error('Error in plugin:', error);
                res.status(500).send('Internal Server Error');
            }
        } else {
            next();
        }
    }
    runPlugin();
}

// Apply plugins to all routes
app.use(applyPlugins);

// Example route
app.get('/', (req, res) => {
    res.send('Hello World!');
});

app.listen(port, () => {
    console.log(`API Gateway listening at http://localhost:${port}`);
});